Properties.PersistedHtmlValue:
{%- assign groupId = Workflow | Attribute:&#39;Group&#39;,&#39;Id&#39; -%}
{%- assign locationId = Workflow | Attribute:&#39;Location&#39;,&#39;Id&#39; -%}
{%- assign schedule = Activity | Attribute:&#39;Schedule&#39;,&#39;Object&#39; -%}
{%- assign scheduleId = schedule.Id -%}
{%- assign scheduleDate = schedule.EffectiveStartDate | Date:&#39;yyyy-MM-dd&#39; -%}

{%- attendanceoccurrence where:&#39;GroupId == {{ groupId }} &amp;&amp; LocationId == {{ locationId }} &amp;&amp; ScheduleId == {{ scheduleId }} &amp;&amp; OccurrenceDate == &quot;{{ scheduleDate }}&quot;&#39; limit:&#39;1&#39; select:&#39;Id&#39; securityenabled:&#39;false&#39; -%}
    {{- attendanceoccurrence -}}
{%- endattendanceoccurrence -%}

{%- assign groupId = Workflow | Attribute:&#39;Group&#39;,&#39;Id&#39; -%}
{%- assign locationId = Workflow | Attribute:&#39;Location&#39;,&#39;Id&#39; -%}
{%- assign scheduleId = Activity | Attribute:&#39;Schedule&#39;,&#39;Id&#39; -%}
{%- assign occurrenceId = Activity | Attribute:&#39;OccurrenceId&#39; -%}

{%- sql return:&#39;Results&#39; groupid:{{ groupId }} locationid:{{ locationId }} scheduleid:{{ scheduleId }} occurrenceid:{{ occurrenceId }} -%}
    WITH SlotsDesiredCTE AS (
        SELECT  gl.[GroupId] AS &#39;GroupId&#39;
                , gl.[LocationId] AS &#39;LocationId&#39;
                , glsc.[ScheduleId] AS &#39;ScheduleId&#39;
                ,SUM(glsc.[DesiredCapacity]) AS &#39;SlotCount&#39;
        FROM    [dbo].[Group] g
        INNER JOIN [dbo].[GroupLocation] gl
            ON  gl.[GroupId] = g.[Id]
            AND gl.[LocationId] = @locationid
        INNER JOIN [dbo].[Location] l
            ON  l.[Id] = gl.[LocationId]
        INNER JOIN [dbo].[GroupLocationScheduleConfig] glsc
            ON  glsc.[GroupLocationId] = gl.[Id]
            AND glsc.[ScheduleId] = @scheduleid
        WHERE   g.[Id] = @groupid
            AND g.[IsActive] = &#39;true&#39;
            AND g.[IsArchived] != &#39;true&#39;
            AND g.[DisableScheduling] != &#39;true&#39;
        GROUP BY gl.[GroupId]
                , gl.[LocationId]
                , glsc.[ScheduleId]
    ),

    SlotsFilledCTE AS (
        SELECT  gl.[GroupId] AS &#39;GroupId&#39;
                , gl.[LocationId] AS &#39;LocationId&#39;
                , glsc.[ScheduleId] AS &#39;ScheduleId&#39;
                , COUNT(a.[Id]) AS &#39;SlotCount&#39;
        FROM    [dbo].[Group] g
        INNER JOIN [dbo].[GroupLocation] gl
            ON  gl.[GroupId] = g.[Id]
            AND gl.[LocationId] = @locationid
        INNER JOIN [dbo].[Location] l
            ON  l.[Id] = gl.[LocationId]
        INNER JOIN [dbo].[GroupLocationScheduleConfig] glsc
            ON  glsc.[GroupLocationId] = gl.[Id]
            AND glsc.[ScheduleId] = @scheduleid
        INNER JOIN [dbo].[Schedule] s
            ON  s.[Id] = glsc.[ScheduleId]
            AND s.[Id] = @scheduleid
        LEFT OUTER JOIN [dbo].[AttendanceOccurrence] ao
            ON  ao.[GroupId] = g.[Id]
            AND ao.[LocationId] = l.[Id]
            AND ao.[ScheduleId] = glsc.[ScheduleId]
            AND ao.[OccurrenceDate] = s.[EffectiveStartDate]
        LEFT OUTER JOIN [dbo].[Attendance] a
            ON  a.[OccurrenceId] = ao.[Id]
            AND a.[ScheduledToAttend] = &#39;true&#39;
        WHERE   g.[Id] = @groupid
            AND g.[IsActive] = &#39;true&#39;
            AND g.[IsArchived] != &#39;true&#39;
            AND g.[DisableScheduling] != &#39;true&#39;
        GROUP BY gl.[GroupId]
                , gl.[LocationId]
                , glsc.[ScheduleId]
    )

    SELECT  desiredCTE.SlotCount - filledCTE.SlotCount AS &#39;SlotsAvailable&#39;
    FROM    SlotsDesiredCTE desiredCTE
    INNER JOIN  SlotsFilledCTE filledCTE
        ON  filledCTE.GroupId = desiredCTE.GroupId
        AND filledCTE.LocationId = desiredCTE.LocationId
        AND filledCTE.ScheduleId = desiredCTE.ScheduleId
{%- endsql -%}

{{- Results[0].SlotsAvailable | AsInteger -}}

