{%- assign servicesFull = Workflow | Attribute:'ServicesFull' | Default:'' | Split:setDelimiter -%}
{%- assign fullCount = servicesFull | Size -%}
{%- assign servicesScheduled = Workflow | Attribute:'ServicesScheduled' | Default:'' | Split:setDelimiter -%}
{%- assign scheduledCount = servicesScheduled | Size -%}

{% if person.FullName != CurrentPerson.FullName %}
    {% assign prsnName = person.NickName %}
{% else %}
    {% assign prsnName = 'you' %}
{% endif %}

{%- assign group = Workflow | Attribute:'Group','Object' -%}
{%- assign location = Workflow | Attribute:'Location','Object' -%}
<div class="signup-role">
    {{ group.Campus }} - {{ group | Attribute:'PublicLabel' }}{%- if location.LocationTypeValueId != 181 -%} - {{ location.Name | Remove:' - SERVE' }}{%- endif -%}
</div>

{% if fullCount > 0 %}
    <div class="alert alert-danger">
        {% if fullCount > 1 %}
            Unfortunately, the following services filled up before we could add {{ prsnName }} to them:
            <ul>
                {% for service in servicesFull %}
                    <li>{{ service }}</li>
                {% endfor %}
            </ul>
        {% else %}
            Unfortunately, the {{ servicesFull | First }} service filled up before we could add {{ prsnName }} to it.
        {% endif %}
    </div>
{% endif %}

