    <div class="alert alert-success">
        {% if scheduledCount > 1 %}
            We have added {{ prsnName }} to the schedule for the following services:
            <ul>
                {% for service in servicesScheduled %}
                    <li>{{ service }}</li>
                {% endfor %}
            </ul>
        {% else %}
            We have added {{ prsnName }} to the schedule for the {{ servicesScheduled | First }} service.<br>
        {% endif %}
        <em><small>
            If you have any questions or need to make changes to this sign-up please email <a href="mailto:{{ contactEmail }}">{{ contactEmail }}</a>.
        </small></em>
    </div>
{% endif %}
{% assign holiday = Workflow | Attribute:'Holiday' %}
{% if holiday == 'Holiday' %}
    <a href="/holidayserve">Return to Sign Up page</a>
{% else %}
    <a href="/serve{{ holiday | Downcase }}">Return to Sign Up page</a>
{% endif %}

